  registerExtendedRoutes(app, rateLimit);
  registerEnrichedPartsRoutes(app);

  logger.info("WorkOrdersRoutes", "Extended routes registered (clone, history, costs, parts, completions, enriched)");
}

export type { RateLimitMiddleware } from "./types";

/**
 * Work Order Extended Routes
 *
 * Clone, history, and costs management.
 */

import type { Express, Request, Response } from "express";
import { insertMaintenanceCostSchema } from "@shared/schema-runtime";
import { workOrderAppService as workOrderService } from "../application";
import { requireOrgId, AuthenticatedRequest } from "../../../middleware/auth";
import { recordAndPublish } from "../../../sync-events";
import { cloneWorkOrderSchema } from "./schemas";
import { withErrorHandling, sendNotFound, sendCreated } from "../../../lib/route-utils";
import type { RateLimitMiddleware } from "./types";

export function registerExtendedRoutes(app: Express, rateLimit: RateLimitMiddleware) {
  const { writeOperationRateLimit } = rateLimit;

  app.post("/api/work-orders/:id/clone", requireOrgId, writeOperationRateLimit,
    withErrorHandling("clone work order", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const workOrderId = req.params.id;

      const parseResult = cloneWorkOrderSchema.safeParse(req.body);
      if (!parseResult.success) {
        return res.status(400).json({
          message: "Invalid clone options",
          errors: parseResult.error.flatten().fieldErrors,
        });
      }

      const validatedData = parseResult.data;
      const options: {
        plannedStartDate?: Date;
        plannedEndDate?: Date;
        includeTasks?: boolean;
        includeParts?: boolean;
      } = {
        includeTasks: validatedData.includeTasks ?? true,
        includeParts: validatedData.includeParts ?? true,
      };

      if (validatedData.plannedStartDate !== undefined && validatedData.plannedStartDate !== null) {
        options.plannedStartDate = new Date(validatedData.plannedStartDate);
      }

      if (validatedData.plannedEndDate !== undefined && validatedData.plannedEndDate !== null) {
        options.plannedEndDate = new Date(validatedData.plannedEndDate);
      }

      const clonedWorkOrder = await workOrderService.cloneWorkOrder(workOrderId, orgId, options);
      await recordAndPublish("work_order", clonedWorkOrder.id, "create", clonedWorkOrder, (req as AuthenticatedRequest).user?.id);

      sendCreated(res, clonedWorkOrder);
    })
  );

  app.get("/api/work-orders/:id/history", requireOrgId,
    withErrorHandling("fetch work order history", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const workOrderId = req.params.id;

      const historyEntries = await workOrderService.getWorkOrderHistory(workOrderId, orgId);
      const inventoryMovements = await workOrderService.getInventoryMovementsByWorkOrder(workOrderId, orgId);

      res.json({
        history: historyEntries,
        inventoryMovements,
      });
    })
  );

  app.post("/api/work-orders/:id/costs", requireOrgId, writeOperationRateLimit,
    withErrorHandling("create maintenance cost", async (req: Request, res: Response) => {
      const costData = insertMaintenanceCostSchema.parse({
        ...req.body,
        workOrderId: req.params.id,
      });
      const cost = await workOrderService.createMaintenanceCost(costData);
      sendCreated(res, cost);
    })
  );

  app.get("/api/work-orders/:id/costs", requireOrgId,
    withErrorHandling("fetch maintenance costs", async (req: Request, res: Response) => {
      const costs = await workOrderService.getMaintenanceCostsByWorkOrder(req.params.id);
      res.json(costs);
    })
  );

  app.post("/api/work-orders/:id/service-orders", requireOrgId, writeOperationRateLimit,
    withErrorHandling("create service order", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const workOrderId = req.params.id;
      const workOrder = await workOrderService.getWorkOrderById(workOrderId, orgId);
      if (!workOrder) { return sendNotFound(res, "Work order"); }

      const { serviceProviderId, scheduledStartDate, scheduledEndDate, scope, serviceDetails, estimatedDurationHours, quotedAmount, currency, specialRequirements } = req.body;
      if (!serviceProviderId) { return res.status(400).json({ message: "serviceProviderId is required" }); }

      const { serviceOrderRepo } = await import("../../../service-orders");
      const soNumber = await serviceOrderRepo.generateSoNumber(orgId);
      const so = await serviceOrderRepo.createServiceOrder({
        orgId,
        workOrderId,
        serviceProviderId,
        soNumber,
        scheduledStartDate: scheduledStartDate ? new Date(scheduledStartDate) : undefined,
        scheduledEndDate: scheduledEndDate ? new Date(scheduledEndDate) : undefined,
        scope,
        serviceDetails,
        estimatedDurationHours,
        quotedAmount,
        currency,
        specialRequirements,
      });

      sendCreated(res, so);
    })
  );

  app.get("/api/work-orders/:id/service-orders", requireOrgId,
    withErrorHandling("fetch service orders", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const { serviceOrderRepo } = await import("../../../service-orders");
      const orders = await serviceOrderRepo.listServiceOrders(orgId, { workOrderId: req.params.id });
      res.json(orders);
    })
  );

  app.post("/api/work-orders/:id/purchase-requests", requireOrgId, writeOperationRateLimit,
    withErrorHandling("create purchase request", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const workOrderId = req.params.id;
      const workOrder = await workOrderService.getWorkOrderById(workOrderId, orgId);
      if (!workOrder) { return sendNotFound(res, "Work order"); }

      const { supplierId, items, notes, priority, requestedDeliveryDate } = req.body;
      if (!items || !Array.isArray(items) || items.length === 0) {
        return res.status(400).json({ message: "At least one item is required" });
      }

      const purchaseRepo = await import("../../../purchasing/repository");
      const requestNumber = await purchaseRepo.generateRequestNumber(orgId);
      const authReq = req as AuthenticatedRequest;
      const userId = authReq.user?.id || req.headers["x-user-id"] as string || "system";
      const pr = await purchaseRepo.createPurchaseRequest({
        orgId,
        workOrderId,
        requestNumber,
        requestedBy: userId,
        vesselId: workOrder.vesselId,
        supplierId: supplierId || undefined,
        notes: notes || undefined,
        requiredByDate: requestedDeliveryDate ? new Date(requestedDeliveryDate) : undefined,
        status: "draft",
      });

      const createdItems = [];
      const skippedItems: Array<{ description?: string; reason: string }> = [];
      for (const item of items) {
        if (item.partId) {
          const createdItem = await purchaseRepo.addPurchaseRequestItem({
            orgId,
            prId: pr.id,
            partId: item.partId,
            supplierId: item.supplierId,
            quantity: item.quantity || 1,
            uom: item.uom,
            remarks: item.notes || item.description,
          });
          createdItems.push(createdItem);
        } else {
          skippedItems.push({ description: item.description, reason: "partId is required for purchase request items" });
        }
      }

      sendCreated(res, { 
        ...pr, 
        items: createdItems, 
        skippedItems: skippedItems.length > 0 ? skippedItems : undefined 
      });
    })
  );

  app.get("/api/work-orders/:id/purchase-requests", requireOrgId,
    withErrorHandling("fetch purchase requests", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const purchaseRepo = await import("../../../purchasing/repository");
      const prs = await purchaseRepo.listPurchaseRequests({ orgId, workOrderId: req.params.id });
      res.json(prs);
    })
  );
}

/**
 * Work Orders Core Routes
 *
 * Basic CRUD operations for work orders: list, get, create, update, delete.
 */

import type { Express, Request, Response } from "express";
import { insertWorkOrderSchema, updateWorkOrderSchema } from "@shared/schema-runtime";
import { workOrderAppService as workOrderService } from "../application";
import { safeDbOperation } from "../../../error-handling";
import { requireOrgId, requireOrgIdAndValidateBody, AuthenticatedRequest } from "../../../middleware/auth";
import { withErrorHandling, sendNotFound, sendCreated, sendDeleted } from "../../../lib/route-utils";
import type { RateLimitMiddleware } from "./types";

export function registerCoreRoutes(app: Express, rateLimit: RateLimitMiddleware) {
  const { writeOperationRateLimit, criticalOperationRateLimit } = rateLimit;

  app.get("/api/work-orders", requireOrgId,
    withErrorHandling("fetch work orders", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const equipmentId = req.query.equipmentId as string;

      const vesselId = req.query.vesselId as string | undefined;
      const engineerId = req.query.engineerId as string | undefined;
      const status = req.query.status as string | undefined;
      const priority = req.query.priority as string | undefined;
      const dueDateFromStr = req.query.dueDateFrom as string | undefined;
      const dueDateToStr = req.query.dueDateTo as string | undefined;
      const equipmentCategory = req.query.equipmentCategory as string | undefined;
      const search = req.query.search as string | undefined;
      const workOrderType = req.query.workOrderType as string | undefined;

      const filters = {
        vesselId: vesselId || undefined,
        assignedCrewId: engineerId || undefined,
        status: status || undefined,
        priority: priority || undefined,
        dueDateFrom: dueDateFromStr ? new Date(dueDateFromStr) : undefined,
        dueDateTo: dueDateToStr ? new Date(dueDateToStr) : undefined,
        equipmentCategory: equipmentCategory || undefined,
        search: search || undefined,
        workOrderType: workOrderType || undefined,
      };

      const limitParam = req.query.limit as string | undefined;
      const offsetParam = req.query.offset as string | undefined;

      if (limitParam !== undefined || offsetParam !== undefined) {
        const limit = limitParam ? Number.parseInt(limitParam, 10) : undefined;
        const offset = offsetParam ? Number.parseInt(offsetParam, 10) : undefined;

        if (
          limit === undefined ||
          offset === undefined ||
          !Number.isFinite(limit) ||
          !Number.isFinite(offset)
        ) {
          return res.status(400).json({
            message: "Both limit and offset must be provided as valid numbers for pagination",
          });
        }

        if (limit < 1 || limit > 100) {
          return res.status(400).json({ message: "Limit must be between 1 and 100" });
        }

        if (offset < 0) {
          return res.status(400).json({ message: "Offset must be non-negative" });
        }

        const result = await workOrderService.listWorkOrdersPaginated(
          equipmentId,
          orgId,
          limit,
          offset,
          filters
        );
        res.json({
          data: result.items,
          total: result.total,
          limit,
          offset,
          hasMore: offset + result.items.length < result.total,
        });
      } else {
        const workOrders = await workOrderService.listWorkOrders(equipmentId, orgId, filters);
        res.json(workOrders);
      }
    })
  );

  app.get("/api/work-orders/:id", requireOrgId,
    withErrorHandling("fetch work order", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const workOrder = await workOrderService.getWorkOrderById(req.params.id, orgId);

      if (!workOrder) {
        return sendNotFound(res, "Work order");
      }

      res.json(workOrder);
    })
  );

  app.post("/api/work-orders", requireOrgIdAndValidateBody, writeOperationRateLimit,
    withErrorHandling("create work order", async (req: Request, res: Response) => {
      const processedBody = {
        ...req.body,
        scheduledDate: req.body.scheduledDate ? new Date(req.body.scheduledDate) : undefined,
        completedDate: req.body.completedDate ? new Date(req.body.completedDate) : undefined,
        plannedStartDate: req.body.plannedStartDate
          ? new Date(req.body.plannedStartDate)
          : undefined,
        plannedEndDate: req.body.plannedEndDate ? new Date(req.body.plannedEndDate) : undefined,
      };

      const orderData = insertWorkOrderSchema.parse(processedBody);

      const workOrder = await safeDbOperation(
        () => workOrderService.createWorkOrder(orderData, (req as AuthenticatedRequest).user?.id),
        "createWorkOrder"
      );

      sendCreated(res, workOrder);
    })
  );

  app.post("/api/work-orders/with-suggestions", requireOrgIdAndValidateBody, writeOperationRateLimit,
    withErrorHandling("create work order with suggestions", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      const orderData = insertWorkOrderSchema.parse(req.body);

      const result = await safeDbOperation(
        () => workOrderService.createWorkOrderWithSuggestions(orderData, orgId, (req as AuthenticatedRequest).user?.id),
        "createWorkOrderWithSuggestions"
      );

      sendCreated(res, result);
    })
  );

  app.put("/api/work-orders/:id", requireOrgIdAndValidateBody, writeOperationRateLimit,
    withErrorHandling("update work order", async (req: Request, res: Response) => {
      const orderData = updateWorkOrderSchema.parse(req.body);
      const workOrder = await workOrderService.updateWorkOrder(
        req.params.id,
        orderData,
        (req as AuthenticatedRequest).user?.id
      );

      res.json(workOrder);
    })
  );

  app.delete("/api/work-orders/:id", requireOrgId, criticalOperationRateLimit,
    withErrorHandling("delete work order", async (req: Request, res: Response) => {
      const orgId = (req as AuthenticatedRequest).orgId;
      await workOrderService.deleteWorkOrder(req.params.id, orgId, (req as AuthenticatedRequest).user?.id);
      sendDeleted(res);
    })
  );
}

